import { Card, Stack, Row, Text, Divider, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * Weather Card Component
 * Displays current weather and 5-day forecast with clean visual hierarchy
 */
export default function WeatherCard({
  city = 'London',
  temperature = 22,
  condition = 'Sunny',
  humidity = 65,
  windSpeed = 15,
  unit = '°C',
  forecast = [],
}: Props) {
  const { motionEnabled } = useMotion();

  // Map weather conditions to emoji icons
  const getWeatherIcon = (cond: string): string => {
    const iconMap: Record<string, string> = {
      'sunny': '☀️',
      'cloudy': '☁️',
      'rainy': '🌧️',
      'snowy': '❄️',
      'partly cloudy': '⛅',
      'stormy': '⛈️',
      'windy': '💨',
      'foggy': '🌫️',
      'clear': '🌙',
      'drizzle': '🌦️',
    };
    return iconMap[cond.toLowerCase()] || '🌤️'; // default fallback
  };

  const conditionIcon = getWeatherIcon(condition);

  return (
    <>
      <MotionKeyframes />
      <Card
        padding="24"
        shadow="md"
        border={true}
        style={{
          backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
          borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        }}
      >
        <Stack direction="vertical" gap={16} align="stretch">
          {/* Header Section: City and Condition */}
          <Row gap={8} align="center" justify="between">
            <Text
              variant="h3"
              weight="bold"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {city}
            </Text>
            <Text
              variant="body"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              {condition}
            </Text>
          </Row>

          {/* Main Temperature Section */}
          <Stack
            direction="vertical"
            gap={12}
            align="center"
            style={{
              padding: 'var(--ggui-spacing-4, 16px)',
              backgroundColor: 'var(--ggui-color-surface, #fafafa)',
              borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
            }}
          >
            {/* Large Temperature Display */}
            <Text
              variant="h1"
              weight="bold"
              color="var(--ggui-color-primary-600, #0284c7)"
              align="center"
              style={{
                fontSize: 'var(--ggui-font-size-4xl, 36px)',
                letterSpacing: '-0.025em',
              }}
            >
              {temperature}{unit}
            </Text>

            {/* Weather Icon */}
            <div
              role="img"
              aria-label={condition}
              style={{
                fontSize: '64px',
                lineHeight: '1',
              }}
            >
              {conditionIcon}
            </div>
          </Stack>

          {/* Details Grid: Humidity and Wind Speed */}
          <Row
            gap={16}
            justify="between"
            align="center"
            style={{
              padding: 'var(--ggui-spacing-4, 16px)',
            }}
          >
            {/* Humidity Box */}
            <Stack
              direction="vertical"
              gap={4}
              align="center"
              style={{ flex: 1 }}
            >
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Humidity
              </Text>
              <Text
                variant="body"
                weight="semibold"
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {humidity}%
              </Text>
            </Stack>

            {/* Divider between humidity and wind */}
            <div
              style={{
                width: '1px',
                height: '40px',
                backgroundColor: 'var(--ggui-color-outline, #d4d4d8)',
              }}
            />

            {/* Wind Speed Box */}
            <Stack
              direction="vertical"
              gap={4}
              align="center"
              style={{ flex: 1 }}
            >
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Wind Speed
              </Text>
              <Text
                variant="body"
                weight="semibold"
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {windSpeed} km/h
              </Text>
            </Stack>
          </Row>

          {/* Divider */}
          <Divider orientation="horizontal" margin={8} />

          {/* 5-Day Forecast Strip */}
          {forecast.length > 0 && (
            <Stack direction="vertical" gap={8}>
              <Text
                variant="label"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
                weight="semibold"
              >
                5-Day Forecast
              </Text>
              <Row
                gap={8}
                align="stretch"
                justify="start"
                wrap={true}
                style={{
                  overflowX: 'auto',
                  paddingBottom: 'var(--ggui-spacing-2, 8px)',
                }}
              >
                {forecast.map((item, index) => (
                  <Card
                    key={index}
                    padding="12"
                    shadow="sm"
                    border={true}
                    style={{
                      backgroundColor: 'var(--ggui-color-surface, #fafafa)',
                      borderColor: 'var(--ggui-color-outline, #d4d4d8)',
                      minWidth: '100px',
                      flex: '0 0 auto',
                      animation: motionEnabled
                        ? `${animation.scaleIn}`
                        : 'none',
                      animationDelay: motionEnabled ? `${index * 50}ms` : '0ms',
                    }}
                  >
                    <Stack
                      direction="vertical"
                      gap={4}
                      align="center"
                      justify="center"
                    >
                      {/* Forecast Day */}
                      <Text
                        variant="label"
                        align="center"
                        weight="medium"
                        color="var(--ggui-color-onSurface, #18181b)"
                      >
                        {item.day || `Day ${index + 1}`}
                      </Text>

                      {/* Forecast Icon */}
                      {item.icon && (
                        <div
                          style={{
                            fontSize: '40px',
                            lineHeight: '1',
                          }}
                        >
                          {item.icon}
                        </div>
                      )}

                      {/* Forecast Temperatures */}
                      <Text
                        variant="caption"
                        align="center"
                        color="var(--ggui-color-onSurface, #18181b)"
                        weight="semibold"
                      >
                        {item.high !== undefined || item.low !== undefined
                          ? `${item.high ?? '–'}° / ${item.low ?? '–'}°`
                          : '– / –'}
                      </Text>
                    </Stack>
                  </Card>
                ))}
              </Row>
            </Stack>
          )}
        </Stack>
      </Card>
    </>
  );
}

import { useEffect, useRef, useState } from 'react';
import {
  Card,
  Stack,
  Row,
  Text,
  Input,
  Button,
  Badge,
  Box,
  Icon,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Array<Message>;
  onSend?: (payload: { text: string; timestamp: string }) => void;
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function ChatInterface({
  title = '',
  currentUser = '',
  participantCount,
  messages = [],
  onSend,
  onSendMessage,
}: Props) {
  const [messageInput, setMessageInput] = useState('');
  const [lastRenderedMessageCount, setLastRenderedMessageCount] = useState(0);
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const { motionEnabled } = useMotion();

  useEffect(() => {
    scrollToBottom();
  }, []);

  useEffect(() => {
    if (messages.length > lastRenderedMessageCount) {
      setTimeout(scrollToBottom, 0);
      setLastRenderedMessageCount(messages.length);
    }
  }, [messages, lastRenderedMessageCount]);

  const scrollToBottom = () => {
    if (scrollContainerRef.current) {
      scrollContainerRef.current.scrollTop = scrollContainerRef.current.scrollHeight;
    }
  };

  const handleSend = () => {
    const trimmedText = messageInput.trim();
    if (!trimmedText) return;

    const payload = {
      text: trimmedText,
      timestamp: new Date().toISOString(),
    };

    onSend?.(payload);
    onSendMessage?.(payload);
    setMessageInput('');
  };

  const groupedMessages = messages.reduce(
    (groups: Message[][], msg) => {
      const lastGroup = groups[groups.length - 1];
      if (lastGroup && lastGroup[0].sender === msg.sender) {
        lastGroup.push(msg);
      } else {
        groups.push([msg]);
      }
      return groups;
    },
    []
  );

  const formatTimestamp = (timestamp?: string): string => {
    if (!timestamp) return '';
    try {
      const date = new Date(timestamp);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch {
      return '';
    }
  };

  const isCurrentUserMessage = (sender?: string): boolean => {
    return sender === currentUser;
  };

  return (
    <>
      <MotionKeyframes />
      <Card shadow="md" border padding={0} style={{ display: 'flex', flexDirection: 'column', height: '100%' }}>
        <div style={{ backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)', borderBottom: '1px solid var(--ggui-color-primary-200, #bae6fd)', padding: 'var(--ggui-spacing-4, 16px)' }}>
          <Row gap={8} justify="between" align="center">
            <Text variant="h3" weight="semibold" color="var(--ggui-color-primary-900, #0c4a6e)">{title}</Text>
            {participantCount !== undefined && (
              <Badge variant="primary" size="sm">
                {participantCount} {participantCount === 1 ? 'participant' : 'participants'}
              </Badge>
            )}
          </Row>
        </div>

        <div ref={scrollContainerRef} style={{ flex: 1, overflowY: 'auto', backgroundColor: 'var(--ggui-color-surface, #fafafa)', padding: 'var(--ggui-spacing-4, 16px)', borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)', display: 'flex', flexDirection: 'column', gap: 'var(--ggui-spacing-3, 12px)' }}>
          {groupedMessages.length === 0 ? (
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%' }}>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                No messages yet. Start the conversation!
              </Text>
            </div>
          ) : (
            groupedMessages.map((group, groupIdx) => {
              const isCurrentUser = isCurrentUserMessage(group[0].sender);
              return (
                <Stack key={groupIdx} direction="vertical" gap={4} align={isCurrentUser ? 'end' : 'start'} style={{ animation: !isCurrentUser && motionEnabled ? animation.slideInUp : 'none' }}>
                  {group.map((msg, msgIdx) => (
                    <div key={msgIdx} style={{ maxWidth: '70%', display: 'flex', flexDirection: 'column', alignItems: isCurrentUser ? 'flex-end' : 'flex-start' }}>
                      {msgIdx === 0 && !isCurrentUser && (
                        <Text variant="caption" weight="semibold" color="var(--ggui-color-onSurfaceVariant, #52525b)" style={{ marginBottom: 'var(--ggui-spacing-1, 4px)' }}>
                          {msg.sender || 'Anonymous'}
                        </Text>
                      )}
                      <Box padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)" background={isCurrentUser ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'} borderRadius="var(--ggui-shape-radius-lg, 12px)" style={{ wordWrap: 'break-word', overflowWrap: 'break-word', whiteSpace: 'pre-wrap' }}>
                        <Text variant="body" color={isCurrentUser ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-onSurface, #18181b)'} weight="normal">
                          {msg.text || ''}
                        </Text>
                      </Box>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" style={{ marginTop: 'var(--ggui-spacing-1, 4px)' }}>
                        {formatTimestamp(msg.timestamp)}
                      </Text>
                    </div>
                  ))}
                </Stack>
              );
            })
          )}
        </div>

        <Stack direction="vertical" gap={8} style={{ backgroundColor: 'var(--ggui-color-surface, #fafafa)', padding: 'var(--ggui-spacing-4, 16px)', borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)' }}>
          <Row gap={8} align="end">
            <Stack direction="vertical" gap={4} style={{ flex: 1 }}>
              <Text variant="label" htmlFor="message-input">Message</Text>
              <Input id="message-input" label="Message" placeholder="Type a message..." value={messageInput} onChange={setMessageInput} disabled={false} />
            </Stack>
            <Button variant="primary" size="sm" onClick={handleSend} disabled={messageInput.trim().length === 0} rightIcon={<Icon name="plus" size={16} />} aria-label="Send message">
              Send
            </Button>
          </Row>
        </Stack>
      </Card>
    </>
  );
}

import { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Box,
  Divider,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function StockTickerDashboard({
  stocks = [],
  lastUpdated = new Date().toISOString(),
}: Props) {
  const [localStocks, setLocalStocks] = useState<Stock[]>(stocks);
  const [displayTimestamp, setDisplayTimestamp] = useState(lastUpdated);
  const [connectionStatus, setConnectionStatus] = useState<'connecting' | 'connected' | 'error'>('connecting');
  const { motionEnabled } = useMotion();

  // Sync local stocks with prop changes
  useEffect(() => {
    if (stocks.length > 0) {
      setLocalStocks(stocks);
      setConnectionStatus('connected');
    }
  }, [stocks]);

  // Sync timestamp with prop changes
  useEffect(() => {
    if (lastUpdated) {
      setDisplayTimestamp(lastUpdated);
    }
  }, [lastUpdated]);

  // Initialize connection status
  useEffect(() => {
    setConnectionStatus('connecting');
    const timer = setTimeout(() => {
      setConnectionStatus('connected');
    }, 500);

    return () => clearTimeout(timer);
  }, []);

  const formatPrice = (price?: number): string => {
    if (price === undefined || price === null || isNaN(price)) return '--';
    return `$${price.toFixed(2)}`;
  };

  const formatChange = (change?: number): string => {
    if (change === undefined || change === null || isNaN(change)) return '--';
    const sign = change >= 0 ? '+' : '';
    return `${sign}${change.toFixed(2)}`;
  };

  const formatChangePercent = (percent?: number): string => {
    if (percent === undefined || percent === null || isNaN(percent)) return '--';
    const sign = percent >= 0 ? '+' : '';
    return `${sign}${percent.toFixed(2)}%`;
  };

  const formatTimestamp = (iso?: string): string => {
    if (!iso) return '--';
    try {
      const date = new Date(iso);
      return date.toLocaleTimeString('en-US', {
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
        hour12: true,
      });
    } catch {
      return '--';
    }
  };

  const isPositiveChange = (change?: number): boolean => {
    return change !== undefined && change !== null && !isNaN(change) && change >= 0;
  };

  const renderArrow = (isPositive: boolean): string => {
    return isPositive ? '▲' : '▼';
  };

  const getChangeColor = (isPositive: boolean): string => {
    return isPositive
      ? 'var(--ggui-color-success-500, #22c55e)'
      : 'var(--ggui-color-error-500, #ef4444)';
  };

  const getCardBorderStyle = (stock: Stock): React.CSSProperties => {
    const isPositive = isPositiveChange(stock.change);
    const borderColor = getChangeColor(isPositive);
    return {
      borderTop: `2px solid ${borderColor}`,
    };
  };

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="xl" padding="24" center>
        <Stack direction="vertical" gap={24}>
          {/* Header */}
          <Row
            direction="horizontal"
            gap={16}
            justify="between"
            align="center"
            wrap={true}
          >
            <div style={{ flex: 1 }}>
              <Text variant="h1" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                Market Watch
              </Text>
            </div>
            <div
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: 'var(--ggui-spacing-2, 8px)',
              }}
            >
              {/* Connection Status Badge */}
              <div
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: 'var(--ggui-spacing-1, 4px)',
                  padding: 'var(--ggui-spacing-1, 4px) var(--ggui-spacing-2, 8px)',
                  borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                  backgroundColor:
                    connectionStatus === 'connected'
                      ? 'var(--ggui-color-success-500, #22c55e)'
                      : connectionStatus === 'error'
                        ? 'var(--ggui-color-error-500, #ef4444)'
                        : 'var(--ggui-color-warning-500, #f59e0b)',
                  fontSize: 'var(--ggui-font-size-xs, 12px)',
                  fontWeight: 'var(--ggui-font-weight-medium, 500)',
                  color: 'var(--ggui-color-neutral-50, #ffffff)',
                }}
                aria-live="assertive"
                aria-label={`Connection status: ${connectionStatus}`}
              >
                {connectionStatus === 'connecting' && '🔄 Connecting...'}
                {connectionStatus === 'connected' && '✓ Live'}
                {connectionStatus === 'error' && '⚠️ Error'}
              </div>

              {/* Last Updated Timestamp */}
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Last Updated:{' '}
                <time dateTime={displayTimestamp} aria-live="polite">
                  {formatTimestamp(displayTimestamp)}
                </time>
              </Text>
            </div>
          </Row>

          {/* Stock Cards Grid */}
          {localStocks.length === 0 ? (
            <Card
              padding="32"
              shadow="sm"
              border={true}
              style={{
                backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              }}
            >
              <Stack direction="vertical" align="center" gap={12}>
                <Text
                  variant="h3"
                  weight="semibold"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  No stocks to display
                </Text>
                <Text
                  variant="body"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  {connectionStatus === 'connecting'
                    ? 'Connecting to market data...'
                    : 'Waiting for stock data'}
                </Text>
              </Stack>
            </Card>
          ) : (
            <Box
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
                gap: 'var(--ggui-spacing-4, 16px)',
                width: '100%',
              }}
            >
              {localStocks.map((stock, index) => {
                const isPositive = isPositiveChange(stock.change);
                const changeColor = getChangeColor(isPositive);

                return (
                  <Card
                    key={stock.symbol || index}
                    padding="16"
                    shadow="sm"
                    border={true}
                    style={{
                      ...getCardBorderStyle(stock),
                      backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      animation: motionEnabled
                        ? `${animation.slideInUp}, opacity 200ms ease-out both`
                        : 'none',
                      animationDelay: motionEnabled ? `${index * 50}ms` : '0ms',
                      transition: 'box-shadow 200ms ease-out',
                    }}
                    role="article"
                    aria-label={`Stock data for ${stock.symbol || 'unknown'}`}
                  >
                    <Stack direction="vertical" gap={12}>
                      {/* Ticker Symbol & Company Name */}
                      <div>
                        <Text
                          variant="h3"
                          weight="bold"
                          color="var(--ggui-color-onSurface, #18181b)"
                        >
                          {stock.symbol || 'N/A'}
                        </Text>
                        <Text
                          variant="body"
                          color="var(--ggui-color-onSurfaceVariant, #52525b)"
                        >
                          {stock.name || 'Unknown Company'}
                        </Text>
                      </div>

                      {/* Divider */}
                      <Divider
                        orientation="horizontal"
                        margin={0}
                        style={{
                          borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
                        }}
                      />

                      {/* Current Price */}
                      <div>
                        <Text
                          variant="h2"
                          weight="bold"
                          color="var(--ggui-color-onSurface, #18181b)"
                        >
                          {formatPrice(stock.price)}
                        </Text>
                      </div>

                      {/* Change Information */}
                      <Row
                        direction="horizontal"
                        gap={8}
                        align="center"
                        style={{
                          transition: 'color 200ms ease-out',
                        }}
                      >
                        <span
                          style={{
                            color: changeColor,
                            fontSize: 'var(--ggui-font-size-lg, 18px)',
                            fontWeight: 'var(--ggui-font-weight-bold, 700)',
                            minWidth: 'var(--ggui-spacing-2, 8px)',
                          }}
                        >
                          {renderArrow(isPositive)}
                        </span>
                        <Text
                          variant="body"
                          weight="semibold"
                          color={changeColor}
                          style={{
                            transition: 'color 200ms ease-out',
                          }}
                        >
                          {formatChange(stock.change)}
                        </Text>
                        <Text
                          variant="label"
                          color={changeColor}
                          style={{
                            transition: 'color 200ms ease-out',
                          }}
                        >
                          ({formatChangePercent(stock.changePercent)})
                        </Text>
                      </Row>
                    </Stack>
                  </Card>
                );
              })}
            </Box>
          )}
        </Stack>
      </Container>
    </>
  );
}

import React from 'react';
import { Card, Stack, Row, Text, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent({
  city = 'City',
  temperature = 0,
  condition = 'Unknown',
  humidity = 0,
  windSpeed = 0,
  unit = 'C',
  forecast = [],
}: Props) {
  const normalizedUnit = unit?.toUpperCase() || 'C';

  return (
    <Card
      padding={24}
      shadow="md"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        color: 'var(--ggui-color-onSurface, #18181b)',
      }}
      aria-label={`Weather in ${city}`}
    >
      <Stack gap={20}>
        <Text
          variant="caption"
          weight="medium"
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
        >
          {city}
        </Text>

        <Row justify="between" align="center">
          <Stack gap={4}>
            <Text
              variant="h1"
              weight="bold"
              color="var(--ggui-color-onSurface, #18181b)"
              style={{ lineHeight: 1 }}
            >
              {`${temperature}°${normalizedUnit}`}
            </Text>
            <Text
              variant="body"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              {condition}
            </Text>
          </Stack>

          <Text
            variant="h2"
