 */
export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = '°C',
  forecast = [],
}: Props) {
  // Map condition strings to simple emojis for visual feedback
  const getConditionEmoji = (cond: string) => {
    const c = (cond || '').toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain') || c.includes('drizzle')) return '🌧️';
    if (c.includes('storm') || c.includes('thunder')) return '⛈️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('mist') || c.includes('fog')) return '🌫️';
    return '⛅';
  };

  return (
    <Card
      padding={24}
      shadow="md"
      style={{
        width: '100%',
        maxWidth: '480px',
        background: 'linear-gradient(135deg, var(--ggui-color-surface, #fafafa), var(--ggui-color-primary-50, #f0f9ff))',
        border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
        borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
      }}
    >
      <Stack gap={24}>
        {/* Header Section: City and Condition */}
        <Row justify="between" align="start">
          <Stack gap={4}>
            <Text variant="h2" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
              {city}
            </Text>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {condition}
            </Text>
          </Stack>
          <Text style={{ fontSize: 'var(--ggui-font-size-4xl, 36px)', lineHeight: 1 }} aria-hidden="true">
            {getConditionEmoji(condition)}
          </Text>
        </Row>

        {/* Current Temperature Section */}
        <Row align="end" gap={4}>
          <Text
            weight="bold"
            style={{
              fontSize: 'var(--ggui-font-size-4xl, 36px)',
              lineHeight: 1,
              color: 'var(--ggui-color-primary-600, #0284c7)',
              letterSpacing: 'var(--ggui-letter-spacing-tight, -0.025em)',
            }}
          >
            {Math.round(temperature)}
          </Text>
          <Text
            variant="h3"
            weight="medium"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
            style={{ paddingBottom: 'var(--ggui-spacing-1, 4px)' }}
          >
            {unit}
          </Text>
        </Row>

        {/* Details Row (Humidity, Wind) */}
        <Row gap={12} wrap>
          <Box
            padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
            borderRadius="var(--ggui-shape-radius-md, 8px)"
            style={{ 
              background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
              flex: '1 1 auto',
            }}
          >
            <Row gap={8} align="center">
              <span role="img" aria-label="Humidity">💧</span>
              <Text variant="label" weight="medium">{humidity}% Humidity</Text>
            </Row>
          </Box>
          <Box
            padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
            borderRadius="var(--ggui-shape-radius-md, 8px)"
            style={{ 
              background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
              flex: '1 1 auto',
            }}
          >
            <Row gap={8} align="center">
              <span role="img" aria-label="Wind speed">💨</span>
