interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>;
}

const CAT_MAP: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-100)',
  'alkaline earth metal': 'var(--ggui-color-warning-100)',
  'transition metal': 'var(--ggui-color-neutral-100)',
  'post-transition metal': 'var(--ggui-color-success-100)',
  'metalloid': 'var(--ggui-color-info-100)',
  'diatomic nonmetal': 'var(--ggui-color-primary-100)',
  'polyatomic nonmetal': 'var(--ggui-color-primary-200)',
  'noble gas': 'var(--ggui-color-neutral-300)',
  'lanthanide': 'var(--ggui-color-primary-50)',
  'actinide': 'var(--ggui-color-error-50)',
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<typeof elements[0] | null>(null);
  const { motionEnabled } = useMotion();

  const filtered = useMemo(() => elements.filter(e => !search || e.name?.toLowerCase().includes(search.toLowerCase()) || e.symbol?.toLowerCase().includes(search.toLowerCase())), [elements, search]);
  const categories = useMemo(() => Array.from(new Set(elements.map(e => e.category).filter(Boolean) as string[])).sort(), [elements]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack gap={32}>
        <Row align="end" justify="between" wrap>
          <Stack gap={4}>
            <Text variant="h1">Periodic Table</Text>
            <Text color="var(--ggui-color-onSurfaceVariant)">Interactive Database</Text>
          </Stack>
          <Box style={{ width: '320px' }}>
            <Text as="label" htmlFor="search-id" variant="label">Search Elements</Text>
            <Input label="Search Elements" id="search-id" value={search} onChange={setSearch} placeholder="Find an element..." />
          </Box>
        </Row>

        <Row gap={12} wrap>
          {categories.map(c => (
            <Row key={c} gap={4} align="center">
              <Box style={{ width: 12, height: 12, borderRadius: 2, backgroundColor: CAT_MAP[c.toLowerCase()] || 'var(--ggui-color-surfaceVariant)', border: '1px solid var(--ggui-color-outline)' }} />
              <Text variant="caption">{c}</Text>
            </Row>
          ))}
        </Row>

        <Box style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-4, 16px)' }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(18, minmax(52px, 1fr))', gridTemplateRows: 'repeat(10, minmax(64px, 1fr))', gap: 4, minWidth: 940 }}>
            {elements.map(e => {
              const active = selected?.atomicNumber === e.atomicNumber;
              const match = filtered.includes(e);
              const color = CAT_MAP[e.category?.toLowerCase() || ''] || 'var(--ggui-color-surfaceVariant)';
              return (
                <div key={e.atomicNumber} onClick={() => setSelected(e)} role="button" tabIndex={0} aria-label={e.name} style={{ gridColumn: e.col, gridRow: e.row, backgroundColor: color, border: active ? '2px solid var(--ggui-color-primary-600)' : '1px solid var(--ggui-color-outline)', borderRadius: 'var(--ggui-shape-radius-sm)', padding: 'var(--ggui-spacing-1, 4px)', cursor: 'pointer', display: 'flex', flexDirection: 'column', position: 'relative', transition: transition.normal, opacity: search && !match ? 0.3 : 1, transform: active ? 'scale(1.1)' : 'scale(1)', zIndex: active ? 10 : 1, boxShadow: active ? 'var(--ggui-shape-shadow-md)' : 'none', outline: 'none' }}>
                  <Text style={{ fontSize: '10px', position: 'absolute', top: 2, left: 4, fontWeight: '500' }}>{e.atomicNumber}</Text>
                  <Stack align="center" justify="center" style={{ flex: 1, pointerEvents: 'none' }}><Text weight="bold" style={{ fontSize: '18px', lineHeight: 1 }}>{e.symbol}</Text></Stack>
                </div>
              );
            })}
          </div>
        </Box>

        <Box style={{ minHeight: 180 }}>
          {selected ? (
            <Card padding="var(--ggui-spacing-6, 24px)" style={{ animation: motionEnabled ? animation.fadeIn : 'none', borderLeft: `8px solid ${CAT_MAP[selected.category?.toLowerCase() || ''] || 'var(--ggui-color-surfaceVariant)'}` }}>
              <Row gap={32} align="start" wrap>
                <Stack align="center" gap={8} style={{ minWidth: 120 }}><Text weight="bold" style={{ fontSize: '36px', lineHeight: 1 }}>{selected.symbol}</Text><Badge variant="outline">#{selected.atomicNumber}</Badge></Stack>
                <Divider orientation="vertical" margin={0} />
                <Stack gap={16} style={{ flex: 1 }}>
                  <Row justify="between" align="center" wrap><Text variant="h2">{selected.name}</Text><Badge variant="primary" size="lg">{selected.category}</Badge></Row>
                  <Row gap={24} wrap>
                    <Stack gap={4}><Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Weight</Text><Text weight="semibold" variant="h3">{selected.atomicWeight} u</Text></Stack>
                    <Stack gap={4}><Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Category</Text><Text weight="semibold" variant="h3">{selected.category}</Text></Stack>
                  </Row>
                </Stack>
              </Row>
            </Card>
          ) : (
            <Card padding="var(--ggui-spacing-8, 32px)"><Stack align="center" justify="center" gap={12} style={{ opacity: 0.5 }}><Icon name="search" size={32} /><Text variant="h3">Element Details</Text><Text>Select an element to view properties.</Text></Stack></Card>
          )}
        </Box>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Button,
  Badge,
  Box,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Array<Message>;
  sendMessage: (payload: { text: string; timestamp: string }) => void;
  onSend?: (payload: { text: string; timestamp: string }) => void;
}

export default function ConverseChat(props: Props) {
  const {
    title = 'Chat',
    currentUser = 'User',
    participantCount,
    messages: propMessages = [],
    sendMessage,
    onSend
  } = props;

  const [messages, setMessages] = useState<Message[]>(propMessages);
  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);
  const { motionEnabled } = useMotion();

  useEffect(() => {
    setMessages(propMessages);
  }, [propMessages]);

  useEffect(() => {
    const handleData = (event: any) => {
      const data = event.detail;
      if (data && data.text) {
        setMessages(prev => [...prev, {
          sender: data.sender || 'Assistant',
          text: data.text,
          timestamp: new Date().toISOString()
        }]);
      }
    };

    if (typeof addEventListener !== 'undefined') {
      addEventListener('ggui:agent-data' as any, handleData);
      return () => removeEventListener('ggui:agent-data' as any, handleData);
    }
  }, []);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleAction = () => {
    if (!inputValue.trim()) return;
    const payload = { text: inputValue.trim(), timestamp: new Date().toISOString() };
    if (sendMessage) sendMessage(payload);
    if (onSend) onSend(payload);
    setMessages(prev => [...prev, { sender: currentUser, ...payload }]);
    setInputValue('');
  };

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-4)">
      <MotionKeyframes />
      <Card padding={0} shadow="md" border style={{ height: '600px', display: 'flex', flexDirection: 'column', backgroundColor: 'var(--ggui-color-surface)' }}>
        <Box padding="var(--ggui-spacing-4)" style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant)', backgroundColor: 'var(--ggui-color-surfaceVariant)' }}>
          <Stack gap={4}>
            <Text variant="h3" weight="bold">{title}</Text>
            {participantCount !== undefined && <Badge variant="info" pill>{participantCount} members</Badge>}
          </Stack>
        </Box>

        <Box ref={scrollRef} style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-4)' }}>
          <Stack gap={8}>
            {messages.map((m, i) => {
              const isMe = m.sender === currentUser;
              const isGrouped = i > 0 && messages[i-1].sender === m.sender;
              return (
                <Stack key={`${i}-${m.timestamp}`} align={isMe ? 'end' : 'start'} gap={2} style={{ animation: motionEnabled ? animation.fadeIn : 'none' }}>
                  {!isGrouped && <Text variant="caption" weight="semibold">{m.sender}</Text>}
                  <Box padding="var(--ggui-spacing-2) var(--ggui-spacing-4)" borderRadius="var(--ggui-shape-radius-lg)" style={{ backgroundColor: isMe ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)', color: isMe ? '#ffffff' : 'var(--ggui-color-onSurface)', maxWidth: '80%' }}>
                    <Text variant="body">{m.text}</Text>
                  </Box>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" style={{ fontSize: '10px' }}>
                    {m.timestamp ? new Date(m.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : ''}
                  </Text>
                </Stack>
              );
            })}
          </Stack>
        </Box>

        <Box padding="var(--ggui-spacing-4)" borderTop="1px solid var(--ggui-color-outlineVariant)">
          <Stack gap={8}>
            <Text variant="label">Message Input</Text>
            <Input label="Message Input" value={inputValue} onChange={(v) => setInputValue(v)} onKeyDown={(e: any) => e.key === 'Enter' && handleAction()} placeholder="Type a message..." />
            <Button variant="primary" onClick={handleAction} disabled={!inputValue.trim()}>Send Message</Button>
          </Stack>
        </Box>
      </Card>
    </Container>
  );
}

