}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * Stock Ticker Dashboard
 * Displays real-time market data with live updates via Stream Contract.
 */
export default function StockTickerDashboard({ stocks: initialStocks = [], lastUpdated: initialLastUpdated }: Props) {
  const [stocks, setStocks] = useState<Stock[]>(initialStocks);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(initialLastUpdated);
  const [isConnecting, setIsConnecting] = useState(true);
  const { motionEnabled } = useMotion();

  useEffect(() => {
    if (initialStocks && initialStocks.length > 0) {
      setStocks(initialStocks);
      setIsConnecting(false);
    }

    if (initialLastUpdated) {
      setLastUpdated(initialLastUpdated);
    }

    const handleAgentData = (event: any) => {
      const data = event.detail;
      if (data) {
        if (Array.isArray(data.stocks)) {
          setStocks(data.stocks);
          setIsConnecting(false);
        }
        if (data.lastUpdated) {
          setLastUpdated(data.lastUpdated);
        }
      }
    };

    // The environment allows addEventListener on the global scope 
    // for Stream Contract support.
    try {
      if (typeof addEventListener === 'function') {
        addEventListener('ggui:agent-data', handleAgentData);
      }
    } catch (e) {
      console.warn('Stream listener could not be initialized');
    }

    return () => {
      try {
        if (typeof removeEventListener === 'function') {
          removeEventListener('ggui:agent-data', handleAgentData);
        }
      } catch (e) {
        // cleanup fail
      }
    };
  }, [initialStocks, initialLastUpdated]);

  const formatTime = (isoString?: string) => {
    if (!isoString) return '---';
    try {
      const date = new Date(isoString);
      return date.toLocaleTimeString([], { 
        hour: '2-digit', 
        minute: '2-digit', 
        second: '2-digit' 
      });
    } catch (e) {
      return '---';
    }
  };

  const formatCurrency = (value?: number) => {
    if (value === undefined || value === null) return '0.00';
    return value.toLocaleString(undefined, { 
      minimumFractionDigits: 2, 
      maximumFractionDigits: 2 
    });
  };

  const formatPercent = (value?: number) => {
    if (value === undefined || value === null) return '0.00';
    return Math.abs(value).toFixed(2);
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack gap={24}>
        <Row justify="between" align="center" wrap>
          <Stack gap={4}>
            <Text variant="h1" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
              Market Watch
            </Text>
            <Row gap={8} align="center">
              <Badge variant={isConnecting ? 'warning' : 'success'} size="sm">
                {isConnecting ? 'Connecting...' : 'Live Data'}
              </Badge>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Last Updated: {formatTime(lastUpdated)}
              </Text>
            </Row>
          </Stack>
        </Row>

        <Divider margin={0} />

        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))',
            gap: 'var(--ggui-spacing-4, 16px)',
            width: '100%',
          }}
        >
          {stocks.length === 0 && !isConnecting ? (
            <Card padding={48}>
              <Stack align="center" justify="center" gap={12}>
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  No stock data currently available.
                </Text>
              </Stack>
            </Card>
          ) : (
            stocks.map((stock, index) => {
              const changeValue = stock.change ?? 0;
              const isPositive = changeValue >= 0;

              const themeColor = isPositive 
                ? 'var(--ggui-color-success-600, #16a34a)' 
                : 'var(--ggui-color-error-600, #dc2626)';

              const borderStyles = {
                borderColor: themeColor,
                borderStyle: 'solid',
                borderWidth: '1px',
              };

              return (
                <Card 
                  key={stock.symbol || index}
                  padding={24}
                  style={{
                    ...borderStyles,
                    transition: transition.colors,
                    animation: motionEnabled ? animation.slideInUp : 'none',
                    animationDelay: `${index * 50}ms`,
                  }}
                >
                  <Stack gap={16}>
                    <Row justify="between" align="start">
                      <Stack gap={2}>
                        <Text variant="h3" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                          {stock.symbol || '---'}
                        </Text>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          {stock.name || '---'}
                        </Text>
                      </Stack>

                      <Row gap={4} align="center">
                         <Text 
                            variant="label" 
                            weight="bold" 
                            color={themeColor}
                          >
                            {isPositive ? '▲' : '▼'} {formatPercent(stock.changePercent)}%
                          </Text>
                      </Row>
                    </Row>

                    <Row align="end" justify="between">
                      <Text variant="h2" weight="bold">
                        ${formatCurrency(stock.price)}
                      </Text>
                      <Stack align="end" gap={0}>
                        <Text 
                          variant="body" 
                          weight="semibold" 
                          color={themeColor}
                        >
                          {isPositive ? '+' : ''}{formatCurrency(stock.change)}
                        </Text>
                      </Stack>
                    </Row>
                  </Stack>
                </Card>
              );
            })
          )}
        </Box>
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Select,
  Checkbox,
  RadioGroup,
  Button,
  Divider,
  Box,
  Icon,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

export interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  onComplete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function OnboardingWizard(props: Props) {
  const { avatarOptions, roleOptions, initialProfile, onComplete } = props;
  const { motionEnabled } = useMotion();
  const [step, setStep] = useState(0);

  const [name, setName] = useState(initialProfile?.name || '');
  const [email, setEmail] = useState(initialProfile?.email || '');
  const [avatar, setAvatar] = useState(initialProfile?.avatar || avatarOptions[0] || '👤');
  const [role, setRole] = useState(initialProfile?.role || roleOptions[0] || '');
  const [emailNotifications, setEmailNotifications] = useState(initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState(initialProfile?.theme || 'light');

  const isValidEmail = (v: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v);

  const isStepValid = useMemo(() => {
    if (step === 0) return name.trim().length > 0 && isValidEmail(email);
    if (step === 1) return role !== '';
    return true;
  }, [step, name, email, role]);

  const steps = ['Profile Setup', 'Preferences', 'Review Details'];

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <MotionKeyframes />
      <Stack gap={32}>
        <Stack gap={12}>
          <Row justify="between" align="end">
            <Stack gap={4}>
              <Text variant="caption">Step {step + 1} of 3</Text>
              <Text variant="h3" weight="bold">{steps[step]}</Text>
            </Stack>
            <Text variant="caption">{Math.round(((step + 1) / 3) * 100)}%</Text>
          </Row>
          <Box background="var(--ggui-color-outlineVariant)" borderRadius="var(--ggui-shape-radius-full)" style={{ height: 6, overflow: 'hidden' }}>
            <Box background="var(--ggui-color-primary-600)" style={{ height: '100%', width: `${((step + 1) / 3) * 100}%`, transition: transition.normal }} />
          </Box>
        </Stack>

        <Card padding={32}>
          <div key={step} style={{ animation: motionEnabled ? animation.fadeIn : 'none' }}>
            {step === 0 && (
              <Stack gap={24}>
                <Input label="Name" placeholder="Full Name" value={name} onChange={setName} required />
                <Input label="Email" type="email" placeholder="Email Address" value={email} onChange={setEmail} required error={email && !isValidEmail(email) ? 'Invalid' : undefined} />
                <Stack gap={12}>
                  <Text variant="label">Avatar</Text>
                  <Row gap={12} wrap>
                    {avatarOptions.map(emoji => (
                      <Box
                        key={emoji}
                        padding={12}
                        borderRadius="var(--ggui-shape-radius-md)"
                        background={avatar === emoji ? 'var(--ggui-color-primary-50)' : 'transparent'}
                        style={{ cursor: 'pointer', border: `2px solid ${avatar === emoji ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)'}`, fontSize: '2rem', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
                        onClick={() => setAvatar(emoji)}
                      >
                        {emoji}
                      </Box>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 1 && (
              <Stack gap={24}>
                <Select label="Role" value={role} onChange={setRole} options={roleOptions.map(r => ({ value: r, label: r }))} required />
                <Checkbox label="Notifications" checked={emailNotifications} onChange={setEmailNotifications} />
                <RadioGroup label="Theme" value={theme} onChange={setTheme} options={[{ value: 'light', label: 'Light' }, { value: 'dark', label: 'Dark' }]} />
              </Stack>
            )}

            {step === 2 && (
              <Box padding={24} background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-lg)">
                <Stack gap={16}>
                  <Row justify="between"><Text variant="label">Name</Text><Text weight="semibold">{name}</Text></Row>
                  <Row justify="between"><Text variant="label">Email</Text><Text weight="semibold">{email}</Text></Row>
                  <Row justify="between"><Text variant="label">Role</Text><Text weight="semibold">{role}</Text></Row>
                </Stack>
              </Box>
            )}
          </div>
          <Divider margin={24} />
          <Row justify="between">
            <Button variant="outline" onClick={() => setStep(s => s - 1)} disabled={step === 0}>Back</Button>
            {step < 2 ? (
              <Button variant="primary" onClick={() => setStep(s => s + 1)} disabled={!isStepValid}>Next</Button>
            ) : (
              <Button variant="primary" onClick={() => onComplete?.({ name, email, avatar, role, emailNotifications, theme })}>Complete</Button>
            )}
          </Row>
        </Card>
      </Stack>
    </Container>
  );
}

import React from 'react';
import {
  Card,
