interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * WeatherCard Component
 * A clean, data-driven weather display component.
 * Uses theme-aware semantic tokens and primitives for a robust visual hierarchy.
 */
export default function WeatherCard({
  city = 'San Francisco',
  temperature = 72,
  condition = 'Sunny',
  humidity = 45,
  windSpeed = 12,
  unit = 'F',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 75, low: 60 },
    { day: 'Tue', icon: '⛅', high: 72, low: 58 },
    { day: 'Wed', icon: '☁️', high: 68, low: 55 },
    { day: 'Thu', icon: '🌧️', high: 62, low: 52 },
    { day: 'Fri', icon: '☀️', high: 70, low: 58 },
  ],
}: Props) {
  // Helper to determine the primary emoji based on the condition string
  const getConditionEmoji = (cond: string) => {
    const c = cond.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('cloud') && (c.includes('sun') || c.includes('partly'))) return '⛅';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain') || c.includes('shower')) return '🌧️';
    if (c.includes('thunder') || c.includes('storm')) return '⛈️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('mist') || c.includes('fog') || c.includes('haze')) return '🌫️';
    return '🌡️';
  };

  return (
    <Container maxWidth="sm">
      <Card padding="var(--ggui-spacing-6, 24px)" shadow="lg">
        <Stack gap={24}>
          {/* Header: Location and Status */}
          <Stack gap={4}>
            <Text variant="h2" weight="bold">
              {city}
            </Text>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Currently
            </Text>
          </Stack>

          {/* Large Hero: Temperature and Main Icon */}
          <Row justify="between" align="center">
            <Stack gap={0}>
              <Row align="start" gap={4}>
                <Text
                  style={{
                    fontSize: 'var(--ggui-font-size-4xl, 3.5rem)',
                    lineHeight: '1',
                    color: 'var(--ggui-color-onSurface, #18181b)',
                    letterSpacing: 'var(--ggui-letter-spacing-tight, -0.025em)',
                  }}
                  weight="bold"
                >
                  {temperature}
                </Text>
                <Text
                  variant="h3"
                  style={{ marginTop: 'var(--ggui-spacing-2, 8px)' }}
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  °{unit}
                </Text>
              </Row>
            </Stack>

            <Stack align="center" gap={4}>
              <span
                role="img"
                aria-label={condition}
                style={{ fontSize: 'var(--ggui-font-size-4xl, 3rem)' }}
              >
                {getConditionEmoji(condition)}
              </span>
              <Text weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                {condition}
              </Text>
            </Stack>
          </Row>

          {/* Secondary Stats Section */}
          <div
            style={{
              backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              padding: 'var(--ggui-spacing-4, 16px)',
              borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
              border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
            }}
          >
            <Row justify="around" align="center">
              <Stack align="center" gap={4}>
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  weight="semibold"
                  style={{ textTransform: 'uppercase', letterSpacing: '0.05em' }}
                >
                  Humidity
                </Text>
                <Text weight="bold" variant="h3">
                  {humidity}%
                </Text>
              </Stack>

              <Divider orientation="vertical" />

              <Stack align="center" gap={4}>
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  weight="semibold"
                  style={{ textTransform: 'uppercase', letterSpacing: '0.05em' }}
                >
                  Wind
                </Text>
                <Text weight="bold" variant="h3">
                  {windSpeed} <span style={{ fontSize: '0.75em', fontWeight: 'normal' }}>km/h</span>
                </Text>
              </Stack>
            </Row>
          </div>

          <Divider />

          {/* 5-Day Forecast Strip */}
          <Row justify="between" align="center" gap={8}>
            {forecast.map((item, index) => (
              <Stack 
                key={`${item.day}-${index}`} 
                align="center" 
                gap={8} 
                style={{ flex: 1, minWidth: 0 }}
              >
                <Text
                  variant="caption"
                  weight="bold"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  align="center"
                >
                  {item.day}
                </Text>
                <span 
                  role="img" 
                  aria-label="forecast-icon" 
                  style={{ fontSize: '1.25rem' }}
                >
                  {item.icon || '🌡️'}
                </span>
                <Stack gap={0} align="center">
                  <Text variant="caption" weight="bold">
                    {item.high}°
                  </Text>
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    {item.low}°
                  </Text>
                </Stack>
              </Stack>
            ))}
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Box,
  Divider,
  Spacer,
  Badge,
  Heading
} from '@ggui-ai/design/primitives';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: ElementData[];
}

const getCategoryColor = (category?: string) => {
  const cat = category?.toLowerCase() || '';
  if (cat.includes('noble gas')) return 'var(--ggui-color-primary-100, #e0f2fe)';
  if (cat.includes('alkali metal')) return 'var(--ggui-color-error-100, #fee2e2)';
  if (cat.includes('alkaline earth')) return 'var(--ggui-color-warning-100, #fef3c7)';
  if (cat.includes('transition metal')) return 'var(--ggui-color-warning-50, #fffbeb)';
  if (cat.includes('post-transition')) return 'var(--ggui-color-neutral-100, #f3f4f6)';
  if (cat.includes('metalloid')) return 'var(--ggui-color-info-100, #ecfeff)';
  if (cat.includes('nonmetal')) return 'var(--ggui-color-success-100, #dcfce7)';
  if (cat.includes('halogen')) return 'var(--ggui-color-primary-50, #f0f9ff)';
  if (cat.includes('lanthanide')) return 'var(--ggui-color-container, #ede9fe)';
  if (cat.includes('actinide')) return 'var(--ggui-color-primary-200, #bae6fd)';
  return 'var(--ggui-color-surfaceVariant, #f4f4f5)';
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  const filteredElements = useMemo(() => {
    if (!searchTerm) return elements;
    const lower = searchTerm.toLowerCase();
    return elements.filter((e) => {
      const n = (e.name || '').toLowerCase();
      const s = (e.symbol || '').toLowerCase();
      const a = (e.atomicNumber || '').toString();
      return n.includes(lower) || s.includes(lower) || a === lower;
    });
  }, [elements, searchTerm]);

  const categories = useMemo(() => {
    const unique = new Set<string>();
    elements.forEach((e) => { if (e.category) unique.add(e.category); });
    return Array.from(unique).sort();
  }, [elements]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap={24}>
        <Heading level={1}>Periodic Table</Heading>
        <Text as="label" htmlFor="search-input">Search Elements</Text>
        <Input label="Search Elements" placeholder="Search..." value={searchTerm} onChange={setSearchTerm} />

        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
            gap: 'var(--ggui-spacing-1, 4px)',
            overflowX: 'auto',
            padding: 'var(--ggui-spacing-2, 8px)',
            background: 'var(--ggui-color-surface, #fafafa)',
            borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
          }}
        >
          {elements.map((el) => {
            const isMatch = filteredElements.some(fe => fe.atomicNumber === el.atomicNumber);
            const isSelected = selectedElement?.atomicNumber === el.atomicNumber;
            const bgColor = getCategoryColor(el.category);

            return (
              <Box
                key={el.atomicNumber}
                onClick={() => setSelectedElement(el)}
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  aspectRatio: '1 / 1',
                  display: 'flex',
                  flexDirection: 'column',
                  padding: 'var(--ggui-spacing-1, 4px)',
                  cursor: 'pointer',
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                  border: isSelected 
                    ? '2px solid var(--ggui-color-primary-600, #0284c7)' 
                    : '1px solid var(--ggui-color-outline, #d4d4d8)',
                  backgroundColor: bgColor,
                  opacity: isMatch ? 1 : 0.25,
                  transition: 'all 200ms ease-out',
                  position: 'relative',
                  zIndex: isSelected ? 10 : 1,
                  transform: isSelected ? 'scale(1.1)' : 'scale(1)',
                }}
              >
                <Text weight="bold" style={{ fontSize: 'var(--ggui-font-size-xs, 12px)' }}>
                  {el.atomicNumber}
                </Text>
                <Spacer size="flex" />
                <Text align="center" weight="bold" style={{ fontSize: 'var(--ggui-font-size-xl, 20px)', lineHeight: 1 }}>
                  {el.symbol}
                </Text>
                <Spacer size="flex" />
                <Text align="center" variant="caption" style={{ fontSize: 'var(--ggui-font-size-xs, 12px)', overflow: 'hidden' }}>
                  {el.name}
                </Text>
              </Box>
            );
          })}
        </Box>

        <Row gap={24} align="stretch" wrap>
          <Box style={{ flex: '1 1 400px' }}>
            <Card padding="var(--ggui-spacing-6, 24px)">
              {selectedElement ? (
                <Stack gap={16}>
                  <Row justify="between" align="center">
                    <Stack gap={4}>
                      <Heading level={2}>{selectedElement.name}</Heading>
                      <Badge variant="info">{selectedElement.category}</Badge>
                    </Stack>
                    <Text variant="h1" color="var(--ggui-color-primary-600)">{selectedElement.symbol}</Text>
                  </Row>
                  <Divider />
                  <Row justify="between" wrap>
                    <Stack gap={4}>
                      <Text variant="label">Atomic Number</Text>
                      <Text variant="h3">{selectedElement.atomicNumber}</Text>
                    </Stack>
                    <Stack gap={4} align="end">
                      <Text variant="label">Atomic Weight</Text>
                      <Text variant="h3">{selectedElement.atomicWeight} u</Text>
                    </Stack>
                  </Row>
                </Stack>
              ) : (
                <Box style={{ height: 'var(--ggui-spacing-12, 48px)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                  <Text color="var(--ggui-color-onSurfaceVariant)">Select an element for details.</Text>
                </Box>
              )}
            </Card>
          </Box>
          <Box style={{ flex: '1 1 300px' }}>
            <Card padding="var(--ggui-spacing-6, 24px)">
              <Stack gap={16}>
                <Text variant="label" weight="bold">Legend</Text>
                <Box style={{ 
                  display: 'grid', 
                  gridTemplateColumns: 'repeat(auto-fill, minmax(var(--ggui-spacing-32, 128px), 1fr))', 
                  gap: 'var(--ggui-spacing-2, 8px)' 
                }}>
                  {categories.map((cat) => (
                    <Row key={cat} gap={8} align="center">
                      <Box style={{ 
                        width: 'var(--ggui-spacing-4, 16px)', 
                        height: 'var(--ggui-spacing-4, 16px)', 
                        borderRadius: 'var(--ggui-shape-radius-sm, 4px)', 
                        backgroundColor: getCategoryColor(cat),
                        border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)'
                      }} />
                      <Text variant="caption">{cat}</Text>
                    </Row>
                  ))}
                </Box>
              </Stack>
            </Card>
          </Box>
        </Row>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Card, Stack, Row, Text, Input, Button, Badge, Box, Icon } from '@ggui-ai/design/primitives';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Message[];
  sendMessage: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent({
  title = 'Chat',
  currentUser = 'User',
  participantCount = 0,
  messages = [],
  sendMessage,
}: Props) {
  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => { scrollRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [messages]);

  const onSend = () => {
    if (!inputValue.trim()) return;
    sendMessage({ text: inputValue.trim(), timestamp: new Date().toISOString() });
    setInputValue('');
  };

  return (
    <Card padding={0} style={{ height: '600px', display: 'flex', flexDirection: 'column', backgroundColor: 'var(--ggui-color-surface, #fafafa)' }}>
      <Box padding="var(--ggui-spacing-4, 16px)" style={{ borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)' }}>
        <Row justify="between" align="center">
          <Text variant="h3" weight="bold">{title}</Text>
          {participantCount !== undefined && <Badge variant="primary">{participantCount}</Badge>}
        </Row>
      </Box>

      <Box style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-4, 16px)', backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)' }}>
        <Stack gap={12}>
          {messages.map((m, i) => (
            <Box key={i} style={{ alignSelf: m.sender === currentUser ? 'flex-end' : 'flex-start', maxWidth: '85%' }}>
              <Stack gap={4} align={m.sender === currentUser ? 'end' : 'start'}>
                {m.sender !== currentUser && (i === 0 || messages[i-1].sender !== m.sender) && <Text variant="label">{m.sender}</Text>}
                <Box padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)" style={{ backgroundColor: m.sender === currentUser ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surface, #fafafa)', color: m.sender === currentUser ? 'white' : 'var(--ggui-color-onSurface, #18181b)', borderRadius: 'var(--ggui-shape-radius-lg, 12px)', boxShadow: 'var(--ggui-shape-shadow-sm)' }}>
                  <Text>{m.text}</Text>
                </Box>
              </Stack>
            </Box>
          ))}
          <div ref={scrollRef} />
        </Stack>
      </Box>

      <Box padding="var(--ggui-spacing-4, 16px)" style={{ borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)' }}>
        <Row gap={8} align="end">
          <Box style={{ flex: 1 }}>
            <Text variant="label">Message Input</Text>
            <Input label="Message Input" value={inputValue} onChange={setInputValue} placeholder="Type a message..." />
          </Box>
          <Button variant="primary" onClick={onSend} disabled={!inputValue.trim()}>Send Message</Button>
        </Row>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Badge,
  Icon,
  Spacer,
  MotionKeyframes,
  useMotion,
  Box,
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * StockTickerDashboard
 * Responsive dashboard showing live stock prices.
 * Updated reactively via props and agent data streams.
 */
export default function StockTickerDashboard({
  stocks = [],
  lastUpdated,
}: Props) {
  const [liveStocks, setLiveStocks] = useState<Stock[]>(stocks);
  const [liveTimestamp, setLiveTimestamp] = useState<string | undefined>(
    lastUpdated
  );
  const [isConnecting, setIsConnecting] = useState(true);
  const { motionEnabled } = useMotion();

  // Handle agent data updates
  useEffect(() => {
    // Sync internal state with incoming props
    if (stocks && stocks.length > 0) {
      setLiveStocks(stocks);
      setLiveTimestamp(lastUpdated || new Date().toISOString());
      setIsConnecting(false);
    }
  }, [stocks, lastUpdated]);

  // Provide decimal formatting
  const formatPrice = (value?: number) =>
    value?.toLocaleString(undefined, {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    }) ?? '0.00';

  const formatTimestamp = (isoString?: string) => {
    if (!isoString) return 'Waiting for update...';
    try {
      return new Date(isoString).toLocaleTimeString(undefined, {
        hour: '2-digit', minute: '2-digit', second: '2-digit'
      });
    } catch (e) {
      return 'Invalid date';
    }
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack gap={24}>
        {/* Header */}
        <Row justify="between" align="end" wrap>
          <Stack gap={4}>
            <Text variant="h2" weight="bold" color="var(--ggui-color-onSurface)">
              Market Watch
            </Text>
            <Row gap={8} align="center">
              <Badge variant={isConnecting && liveStocks.length === 0 ? 'warning' : 'success'} pill>
                <Row gap={6} align="center">
                  <div style={{ 
                    width: 6, 
                    height: 6, 
                    borderRadius: '50%', 
                    background: 'currentColor',
                    opacity: isConnecting ? 0.4 : 1
                  }} />
                  {isConnecting && liveStocks.length === 0 ? 'Connecting...' : 'Live Market Data'}
                </Row>
              </Badge>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                {formatTimestamp(liveTimestamp)}
              </Text>
            </Row>
          </Stack>
        </Row>

        {/* Dashboard Grid */}
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fill, minmax(min(100%, 300px), 1fr))',
            gap: 'var(--ggui-spacing-6, 24px)',
            width: '100%',
          }}
        >
          {liveStocks.map((stock, index) => {
            const isPositive = (stock.change ?? 0) >= 0;
            const trendColor = isPositive
              ? 'var(--ggui-color-success-600, #16a34a)'
              : 'var(--ggui-color-error-600, #dc2626)';
            const trendBorder = isPositive
              ? 'var(--ggui-color-success-500, #22c55e)'
              : 'var(--ggui-color-error-500, #ef4444)';
            const trendBg = isPositive
              ? 'var(--ggui-color-success-50, #f0fdf4)'
              : 'var(--ggui-color-error-50, #fef2f2)';

            return (
              <Card
                key={`${stock.symbol}-${index}`}
                padding={24}
                style={{
                  animation: motionEnabled ? animation.slideInUp : 'none',
                  animationDelay: `${index * 60}ms`,
                  borderLeft: `4px solid ${trendBorder}`,
                  transition: transition.colors,
                  display: 'flex',
                  flexDirection: 'column',
                  background: 'var(--ggui-color-surface)',
                }}
              >
                <Stack gap={16}>
                  <Row justify="between" align="start">
                    <Stack gap={2}>
                      <Text variant="h3" weight="bold" color="var(--ggui-color-onSurface)">
                        {stock.symbol}
                      </Text>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                        {stock.name}
                      </Text>
                    </Stack>
                    <Box padding={6} borderRadius="var(--ggui-shape-radius-full)" background={trendBg}>
                      <Icon
                        name={isPositive ? 'chevron-up' : 'chevron-down'}
                        color={trendColor}
                        size={16}
                      />
                    </Box>
                  </Row>

                  <Stack gap={4}>
                    <Text variant="h2" weight="bold" color="var(--ggui-color-onSurface)">
                      ${formatPrice(stock.price)}
                    </Text>
                    <Row gap={8} align="center">
                      <Text
                        variant="body"
                        weight="semibold"
                        style={{ color: trendColor }}
                      >
                        {isPositive ? '+' : ''}{formatPrice(stock.change)}
                      </Text>
                      <Badge variant={isPositive ? 'success' : 'error'} size="sm">
                        {isPositive ? '▲' : '▼'} {Math.abs(stock.changePercent ?? 0).toFixed(2)}%
                      </Badge>
                    </Row>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </div>

        {liveStocks.length === 0 && (
          <Box padding={64} background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-lg)">
            <Stack align="center" gap={12}>
              <Icon name="search" size={40} color="var(--ggui-color-outline)" />
              <Text align="center" variant="body" color="var(--ggui-color-onSurfaceVariant)">
                No market data available.
              </Text>
            </Stack>
          </Box>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Select,
  Button,
  Divider,
  Checkbox,
  RadioGroup,
  Icon,
  Box,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation, duration, easing } from '@ggui-ai/design/tokens';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  onComplete: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const { avatarOptions = [], roleOptions = [], initialProfile, onComplete } = props;
  const { motionEnabled } = useMotion();
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile?.name ?? '',
    email: initialProfile?.email ?? '',
    avatar: initialProfile?.avatar ?? (avatarOptions[0] || ''),
    role: initialProfile?.role ?? '',
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme ?? 'light'
  });

  const isEmailValid = (e: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e);
  const isStep1Valid = formData.name.trim().length > 0 && isEmailValid(formData.email);
  const isStep2Valid = formData.role !== '';

  const update = (k: string, v: any) => setFormData(p => ({ ...p, [k]: v }));

  const step1 = (
    <Stack gap={20} style={{ animation: motionEnabled ? animation.fadeIn : 'none' }}>
      <Text variant="h3">Profile Setup</Text>
      <Stack gap={4}>
        <Text variant="label">Full Name</Text>
        <Input label="Full Name" placeholder="Enter name" value={formData.name} onChange={v => update('name', v)} required />
      </Stack>
      <Stack gap={4}>
        <Text variant="label">Email Address</Text>
        <Input label="Email Address" type="email" placeholder="email@example.com" value={formData.email} onChange={v => update('email', v)} required />
      </Stack>
      <RadioGroup
        label="Avatar Emoji"
        direction="horizontal"
        value={formData.avatar}
        onChange={(v) => update('avatar', v)}
        options={avatarOptions.map(o => ({ value: o, label: o }))}
      />
    </Stack>
  );

  const step2 = (
    <Stack gap={20} style={{ animation: motionEnabled ? animation.fadeIn : 'none' }}>
      <Text variant="h3">Preferences</Text>
      <Select
        label="Role Selection"
        value={formData.role}
        onChange={(v) => update('role', v)}
        options={roleOptions.map(o => ({ value: o, label: o }))}
        required
      />
      <Checkbox
        label="Email Notifications"
        checked={formData.emailNotifications}
        onChange={(v) => update('emailNotifications', v)}
      />
      <RadioGroup
        label="Theme"
        direction="horizontal"
        value={formData.theme}
        onChange={(v) => update('theme', v)}
        options={[{ value: 'light', label: 'Light' }, { value: 'dark', label: 'Dark' }]}
      />
    </Stack>
  );

  const step3 = (
    <Stack gap={16} style={{ animation: motionEnabled ? animation.fadeIn : 'none' }}>
      <Text variant="h3">Review</Text>
      <Box padding={16} background="var(--ggui-color-surfaceVariant)" borderRadius={8}>
        <Stack gap={12}>
          <Row justify="between"><Text variant="label">Name</Text><Text>{formData.name}</Text></Row>
          <Row justify="between"><Text variant="label">Email</Text><Text>{formData.email}</Text></Row>
          <Row justify="between"><Text variant="label">Role</Text><Text>{formData.role}</Text></Row>
        </Stack>
      </Box>
    </Stack>
  );

  return (
    <Container maxWidth="md">
      <MotionKeyframes />
      <Card shadow="md" padding={32} border>
        <Stack gap={32}>
          <Stack gap={8}>
            <Text variant="h2" align="center" weight="bold">Welcome</Text>
            <div style={{ height: 6, background: 'var(--ggui-color-outlineVariant)', borderRadius: 8, overflow: 'hidden' }}>
              <div style={{ height: '100%', width: `${(step/3)*100}%`, background: 'var(--ggui-color-primary-600)', transition: 'width 200ms ease' }} />
            </div>
          </Stack>

          <Box style={{ minHeight: 300 }}>
            {step === 1 && step1}
            {step === 2 && step2}
            {step === 3 && step3}
          </Box>

          <Divider />

          <Row justify="between">
            <Button variant="outline" onClick={() => setStep(s => s - 1)} disabled={step === 1}>Back</Button>
            {step < 3 ? (
              <Button variant="primary" onClick={() => setStep(s => s + 1)} disabled={step === 1 ? !isStep1Valid : !isStep2Valid}>Next</Button>
            ) : (
              <Button variant="primary" onClick={() => onComplete(formData)}>Complete</Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}
